# ─────────────────────────────────────────────
# RAMY CAN SVG (faithful to actual product)
# ─────────────────────────────────────────────
def ramy_can_svg(flavor="ORANGE", body_color="#C8302A", flavor_color="#F5821F", label="Orange"):
    return f"""<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 80 190' width='80' height='190'>
      <defs>
        <linearGradient id='cg_{flavor}' x1='0' y1='0' x2='1' y2='0'>
          <stop offset='0%' stop-color='#ccc'/>
          <stop offset='30%' stop-color='#f2f2f2'/>
          <stop offset='70%' stop-color='#e0e0e0'/>
          <stop offset='100%' stop-color='#bbb'/>
        </linearGradient>
        <linearGradient id='top_{flavor}' x1='0' y1='0' x2='1' y2='0'>
          <stop offset='0%' stop-color='#4AAAC8'/>
          <stop offset='50%' stop-color='#7DD4EC'/>
          <stop offset='100%' stop-color='#4AAAC8'/>
        </linearGradient>
        <linearGradient id='body_{flavor}' x1='0' y1='0' x2='1' y2='0'>
          <stop offset='0%' stop-color='{body_color}' stop-opacity='0.75'/>
          <stop offset='50%' stop-color='{body_color}'/>
          <stop offset='100%' stop-color='{body_color}' stop-opacity='0.75'/>
        </linearGradient>
      </defs>
      <!-- Can body -->
      <rect x='8' y='22' width='64' height='152' rx='11' fill='url(#cg_{flavor})'/>
      <!-- Blue top band -->
      <rect x='8' y='22' width='64' height='44' rx='11' fill='url(#top_{flavor})'/>
      <!-- Red body -->
      <rect x='8' y='58' width='64' height='116' rx='0' fill='url(#body_{flavor})'/>
      <!-- Bottom cap -->
      <rect x='8' y='152' width='64' height='22' rx='11' fill='url(#body_{flavor})'/>
      <!-- Top ellipse -->
      <ellipse cx='40' cy='22' rx='32' ry='8' fill='#D8D8D8'/>
      <!-- Bottom ellipse -->
      <ellipse cx='40' cy='174' rx='32' ry='8' fill='#B8B8B8'/>
      <!-- Pull tab -->
      <ellipse cx='40' cy='18' rx='10' ry='3' fill='#CCCCCC' stroke='#999' stroke-width='0.8'/>
      <!-- Ramy logo area -->
      <text x='40' y='48' text-anchor='middle' font-family='Georgia,serif' font-size='13' font-weight='900' fill='white' stroke='#C8302A' stroke-width='0.5'>Ramy</text>
      <!-- Flavor name -->
      <text x='40' y='100' text-anchor='middle' font-family='Georgia,serif' font-size='11' font-weight='700' fill='white'>{label}</text>
      <!-- Fruit circle -->
      <circle cx='40' cy='130' r='18' fill='{flavor_color}' opacity='0.85'/>
      <circle cx='40' cy='130' r='12' fill='{flavor_color}' opacity='0.6'/>
      <!-- 240ml -->
      <text x='40' y='158' text-anchor='middle' font-family='Arial' font-size='7' fill='rgba(255,255,255,0.75)'>240ml</text>
    </svg>"""

ORANGE_CAN_SVG  = ramy_can_svg("ORANGE", "#C8302A", "#F5821F", "Orange")
GRENADE_CAN_SVG = ramy_can_svg("GRENADE", "#D03060", "#E84875", "Grenade")

