# ─────────────────────────────────────────────
# HELPERS
# ─────────────────────────────────────────────
def fetch(endpoint):
    try:
        r = requests.get(f"{API_BASE}/{endpoint}", timeout=5)
        return r.json()
    except Exception as e:
        print(f"API error on {endpoint}: {e}")
        return None


def stat_card(title, value, value_color, subtitle, grad_a, grad_b, emoji, anim="f1"):
    return html.Div([
        html.Div(className="card-top-bar", style={
            "background": f"linear-gradient(90deg, {grad_a}, {grad_b})"
        }),
        html.Div(emoji, className="card-emoji-ghost"),
        html.P(title, style={
            "fontSize": "9px", "fontWeight": "700", "color": COLOR_MUTED,
            "textTransform": "uppercase", "letterSpacing": "3px",
            "marginBottom": "10px", "position": "relative", "zIndex": "1"
        }),
        html.H2(value, style={
            "fontSize": "52px", "fontWeight": "900", "color": value_color,
            "fontFamily": "'Fraunces', serif", "lineHeight": "1", "marginBottom": "6px",
            "position": "relative", "zIndex": "1",
        }),
        html.P(subtitle, style={
            "fontSize": "11px", "color": COLOR_MUTED, "fontWeight": "300",
            "position": "relative", "zIndex": "1",
        }),
    ], className=f"glass stat-card {anim}")


def section_header(title, sub=""):
    return html.Div([
        html.P(title, className="sec-title"),
        html.P(sub, className="sec-sub") if sub else None,
        html.Div(className="can-divider"),
    ])


def glass_card(children, extra=None, anim=""):
    style = {"padding": "26px"}
    if extra: style.update(extra)
    return html.Div(children, className=f"glass {anim}", style=style)


